1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface Customer {
9	  yearsWithMHPCO: number;
10	}
11	
12	interface QuoteStep {
13	  op: "quote";
14	  items: Item[];
15	}
16	
17	interface Damage {
18	  itemType: string;
19	  amount: number;
20	}
21	
22	interface ClaimStep {
23	  op: "claim";
24	  policy: number;
25	  incident: { cause: string; damages: Damage[] };
26	}
27	
28	type Step = QuoteStep | ClaimStep;
29	
30	interface Scenario {
31	  customer: Customer;
32	  steps: Step[];
33	}
34	
35	interface QuoteResult {
36	  premium: number;
37	}
38	
39	interface ClaimResult {
40	  payout: number;
41	  remainingCap: number;
42	}
43	
44	type StepResult = QuoteResult | ClaimResult;
45	
46	interface Policy {
47	  items: Item[];
48	  remainingCap: number;
49	}
50	
51	const BASE_PREMIUM: Record<string, number> = {
52	  sword: 100,
53	  amulet: 60,
54	  staff: 80,
55	  potion: 40,
56	  rune: 25,
57	};
58	
59	const INSURANCE_VALUE: Record<string, number> = {
60	  sword: 1000,
61	  amulet: 600,
62	  staff: 800,
63	  potion: 400,
64	  rune: 250,
65	  moonstone: 250,
66	};
67	
68	const KNOWN_ITEM_TYPES = new Set(Object.keys(INSURANCE_VALUE));
69	
70	const DEDUCTIBLE = 100;
71	const CAP_MULTIPLIER = 2;
72	const HIGH_ENCH_PAYOUT_THRESHOLD = 8;
73	const HIGH_ENCH_PAYOUT_RATE = 0.5;
74	
75	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
76	const COMPONENT_BASE = 25;
77	const BLOCK_SIZE = 3;
78	const BLOCK_BASE = 60;
79	
80	const FIRST_INSURANCE_RATE = 0.1;
81	const CURSE_RATE = 0.5;
82	const HIGH_ENCHANTMENT_RATE = 0.3;
83	const HIGH_ENCHANTMENT_THRESHOLD = 5;
84	const LOYALTY_RATE = 0.2;
85	const LOYALTY_THRESHOLD = 2;
86	const FOLLOWUP_RATE = 0.15;
87	const PROCESSING_FEE = 5;
88	const ROUNDING_PRECISION = 6;
89	
90	const componentGroupBase = (count: number): number =>
91	  count === BLOCK_SIZE ? BLOCK_BASE : count * COMPONENT_BASE;
92	
93	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
94	
95	const countBy = <T>(values: T[], key: (value: T) => string): Record<string, number> => {
96	  const counts: Record<string, number> = {};
97	  for (const value of values) {
98	    counts[key(value)] = (counts[key(value)] ?? 0) + 1;
99	  }
100	  return counts;
101	};
102	
103	const withSurcharge = (base: number, rate: number): number => base + base * rate;
104	
105	const isHighlyEnchanted = (item: Item): boolean =>
106	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
107	
108	const itemSurchargeRate = (item: Item): number =>
109	  FIRST_INSURANCE_RATE +
110	  (item.cursed ? CURSE_RATE : 0) +
111	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_RATE : 0);
112	
113	const mainItemPremium = (item: Item): number =>
114	  withSurcharge(BASE_PREMIUM[item.type], itemSurchargeRate(item));
115	
116	const mainItems = (items: Item[]): Item[] => items.filter((item) => !isComponent(item));
117	
118	const mainItemBaseSum = (items: Item[]): number =>
119	  mainItems(items).reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
120	
121	const mainItemTotal = (items: Item[]): number =>
122	  mainItems(items).reduce((sum, item) => sum + mainItemPremium(item), 0);
123	
124	const componentCounts = (items: Item[]): Record<string, number> =>
125	  countBy(items.filter(isComponent), (item) => item.type);
126	
127	const componentBaseSum = (items: Item[]): number =>
128	  Object.values(componentCounts(items)).reduce(
129	    (sum, count) => sum + componentGroupBase(count),
130	    0,
131	  );
132	
133	const componentTotal = (items: Item[]): number =>
134	  withSurcharge(componentBaseSum(items), FIRST_INSURANCE_RATE);
135	
136	const policyBase = (items: Item[]): number => mainItemBaseSum(items) + componentBaseSum(items);
137	
138	const policyDiscount = (items: Item[], rate: number, applies: boolean): number =>
139	  applies ? rate * policyBase(items) : 0;
140	
141	const loyaltyDiscount = (items: Item[], customer: Customer): number =>
142	  policyDiscount(items, LOYALTY_RATE, customer.yearsWithMHPCO >= LOYALTY_THRESHOLD);
143	
144	const followUpDiscount = (items: Item[], isFollowUp: boolean): number =>
145	  policyDiscount(items, FOLLOWUP_RATE, isFollowUp);
146	
147	const roundUpToWhole = (amount: number): number =>
148	  Math.ceil(Number(amount.toFixed(ROUNDING_PRECISION)));
149	
150	const itemPremiumSum = (items: Item[]): number =>
151	  mainItemTotal(items) + componentTotal(items);
152	
153	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number =>
154	  roundUpToWhole(
155	    itemPremiumSum(items) -
156	      loyaltyDiscount(items, customer) -
157	      followUpDiscount(items, isFollowUp) +
158	      PROCESSING_FEE,
159	  );
160	
161	const isQuote = (step: Step): boolean => step.op === "quote";
162	
163	const priorQuoteCount = (steps: Step[], index: number): number =>
164	  steps.slice(0, index).filter(isQuote).length;
165	
166	const insuranceSum = (items: Item[]): number =>
167	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
168	
169	const damageReimbursement = (item: Item | undefined, amount: number): number =>
170	  item && (item.enchantment ?? 0) >= HIGH_ENCH_PAYOUT_THRESHOLD
171	    ? HIGH_ENCH_PAYOUT_RATE * amount
172	    : amount;
173	
174	const damagePayout = (item: Item | undefined, damage: Damage): number =>
175	  damageReimbursement(item, damage.amount) - DEDUCTIBLE;
176	
177	const findInsuredItem = (items: Item[], itemType: string): Item | undefined =>
178	  items.find((item) => item.type === itemType);
179	
180	const incidentPayout = (damages: Damage[], items: Item[]): number =>
181	  damages.reduce(
182	    (sum, damage) => sum + damagePayout(findInsuredItem(items, damage.itemType), damage),
183	    0,
184	  );
185	
186	const assertClaimable = (damages: Damage[], items: Item[]): void => {
187	  const insured = countBy(items, (item) => item.type);
188	  const claimed = countBy(damages, (damage) => damage.itemType);
189	  for (const [itemType, count] of Object.entries(claimed)) {
190	    if (count > (insured[itemType] ?? 0)) {
191	      throw new Error(`Claim references more ${itemType} items than the policy covers`);
192	    }
193	  }
194	};
195	
196	const processClaim = (step: ClaimStep, policies: Policy[]): ClaimResult => {
197	  const policy = policies[step.policy];
198	  assertClaimable(step.incident.damages, policy.items);
199	  const desiredPayout = incidentPayout(step.incident.damages, policy.items);
200	  const payout = Math.min(desiredPayout, policy.remainingCap);
201	  policy.remainingCap -= payout;
202	  return { payout, remainingCap: policy.remainingCap };
203	};
204	
205	const assertKnownItems = (items: Item[]): void => {
206	  const unknown = items.find((item) => !KNOWN_ITEM_TYPES.has(item.type));
207	  if (unknown) {
208	    throw new Error(`Unknown item type: ${unknown.type}`);
209	  }
210	};
211	
212	const processQuote = (
213	  step: QuoteStep,
214	  index: number,
215	  scenario: Scenario,
216	  policies: Policy[],
217	): QuoteResult => {
218	  assertKnownItems(step.items);
219	  const isFollowUp = priorQuoteCount(scenario.steps, index) > 0;
220	  policies[index] = {
221	    items: step.items,
222	    remainingCap: CAP_MULTIPLIER * insuranceSum(step.items),
223	  };
224	  return { premium: quotePremium(step.items, scenario.customer, isFollowUp) };
225	};
226	
227	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
228	  const policies: Policy[] = [];
229	  const results = scenario.steps.map((step, index): StepResult =>
230	    step.op === "claim"
231	      ? processClaim(step, policies)
232	      : processQuote(step, index, scenario, policies),
233	  );
234	  return { results };
235	};
